var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"가장 행복했던 시절의 소녀가 보인다.","JPN":"一番幸せだった頃の少女が見える。","ENG":"In front of me, I see a girl when she was the happiest.","TWN":"我看到了一個少女最快樂的時光。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그녀에겐 자신의 누이가 세상의 전부였고, 숭배하는 모든 것이었다.","JPN":"彼女には自分の姉が世界の全てであり、崇拝する全てであった。","ENG":"Her sister was her whole world and everything she worshipped.","TWN":"對她來說，姊姊就是世界上的一切，是她崇拜的一切。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 나의 그릇된 믿음은… 그 아이의 하나뿐인 세계를 무너뜨렸다.","JPN":"そして我の誤った信仰は……その子どもにとって唯一の世界を壊してしまった。","ENG":"And my wrongful beliefs... destroyed that child's only world.","TWN":"而我扭曲的信仰……毀掉了她唯一的世界。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그녀가 무너트린 세계들의 비명 어린 발자취를 좇으며, 나는 이 끝없는 고통 속을 헤맸다.","JPN":"彼女が崩した世界の悲鳴がこもった足跡を追いかけながら、我はこの果てない苦痛の中で彷徨っていた。","ENG":"I wandered through endless pain, chasing after the trails of the screams from the fallen worlds.","TWN":"我追尋著被她摧毀的世界中的悲鳴，在這無盡的痛苦中徘徊。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그것이 속죄를 위한 고행이라 믿었다.","JPN":"それが罪を償うための苦行だと信じた。","ENG":"I believed that it was a penance for atonement.","TWN":"我原以為可以通過這種苦行來贖罪。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 이제는 알고 있다.","JPN":"でも今ならわかる。","ENG":"But now I know.","TWN":"但是現在我知道了。"},"stage":{"bg":"MS_1202","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"지난 과거의 참혹한 풍경을 되풀이하지 않기 위해선.","JPN":"過ぎ去りし過去の残酷な情景を繰り返さないためには。","ENG":"In order to avoid revisiting the harrowing landscape of the past.","TWN":"為了避免重蹈覆轍，唯有斬斷錯誤的迴圈。"},"stage":{"bg":"MS_1202","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"그늘 아래의 속죄가 아닌 광명 아래의 수호로, 그릇된 순환을 끊어내야 한다는 것을.","JPN":"陰のもとで罪を償うのではなく、光のもとで守護することにより偽った循環を断ち切らなければならないということを。","ENG":"I must sever the wrongful cycle and be the guardian of light, rather than the atoning sinner in the shadows.","TWN":"而這靠的永遠都不會是陰影中的贖罪，而是光明下的守護。"},"stage":{"bg":"MS_1202","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_CA_ARMOR","text":{"KOREA":"세계의 존속을 바라는 수많은 목소리가 나의 귓가를 울린다.","JPN":"世界の存続を願うあまたの声が我の耳に響く。","ENG":"The countless voices of this world that want to live ring within my ears.","TWN":"希望世界存續的無數聲音在我耳邊迴響。"},"stage":{"bg":"MS_1202","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_CA_ARMOR","text":{"KOREA":"이번엔 그 누구도, 살아가는 자들의 희망을 짓밟게 두진 않으리라.","JPN":"今回は誰であっても、生きていく者たちの希望を踏みにじることはできぬ。","ENG":"This time, I will not let anyone trample the hope of the living.","TWN":"這一次，我不會讓任何人踐踏生者的希望。"},"stage":{"bg":"MS_1202","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사라졌어요.","JPN":"消えました。","ENG":"It's gone.","TWN":"不見了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그 커다란 괴물이, 흔적도 없이.","JPN":"あんな大きい化け物が、跡もなく。","ENG":"That huge monster just vanished without a trace.","TWN":"那個大怪物竟然消失得無影無蹤了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…응.","JPN":"……うん。","ENG":"...Yes.","TWN":"……是啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사람들의 믿음으로 강해지는 힘이 있다니. 저런 광경은 처음 봤어.","JPN":"人々の信じる気持ちで強くなる力があるとは。あんな光景は初めて見たよ。","ENG":"Power that grows stronger with people's faith. I've never seen anything like it before.","TWN":"依靠人們的信仰變強的力量，我從沒見過這種場景。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"저 모습이… 모르스 씨의 과거…","JPN":"あの姿が……モールスさんの過去……","ENG":"That's... Mors' past...","TWN":"那是……死神過去的樣子……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"그럼 모르스 씨는 그림자에서 인간으로 다시 돌아온 건가요?","JPN":"ではモールスさんはシャドウからまた人間に戻れたのですか？","ENG":"Does that mean Mors turned back into a human?","TWN":"這麼說，死神已經從暗影恢復成人類了？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"클리파 차원이 그림자의 강한 집념을 받아들인 결과라네.","JPN":"クリファ次元がシャドウの強い執念を受け入れた結果なのだ。","ENG":"It's the result of the Qlipha Dimension accepting the Shadow's strong desire.","TWN":"逆卡巴拉次元接受了暗影的強大執念。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그녀가 인간이 아니기 때문에 벌어질 수 있는 일종의 침식현상이지.","JPN":"彼女が人間ではないから起こすことのできる一種の侵食現象なわけだ。","ENG":"It is a type of Counterside Effect that only occurred because she is not human.","TWN":"正是因為她不是人類，才可能發生這樣的侵蝕現象。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"그렇다면… 모르스 씨의 저 모습은 일시적인 거군요.","JPN":"なら……モールスさんのあの姿は一時的なものなんですね。","ENG":"Then... Mors' appearance is only temporary.","TWN":"這麼說……死神變成那副姿態應該只是暫時的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Correct.","TWN":"是的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 지금의 그녀에겐 그것만으로 충분할 걸세.","JPN":"しかし、今の彼女にはそれだけでも十分だろう。","ENG":"But to her, it is enough.","TWN":"不過對她來說已經足夠了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};